t.script:
document.addEventListener('DOMContentLoaded', function() {
    /* ── Modal buttons ── */
    const addEmpBtn = document.getElementById('btn-add-emp');
    if (addEmpBtn) {
        addEmpBtn.addEventListener('click', function() {
            const empModal = new bootstrap.Modal(document.getElementById('addEmploymentModal'));
            empModal.show();
        });
    }

    const addAchieveBtn = document.getElementById('btn-add-achieve');
    if (addAchieveBtn) {
        addAchieveBtn.addEventListener('click', function() {
            const achieveModal = new bootstrap.Modal(document.getElementById('addAchievementModal'));
            achieveModal.show();
        });
    }

    /* ── Live photo preview ── */
    const photoInput = document.getElementById('ap-photo-input');
    if (photoInput) {
        photoInput.addEventListener('change', function(e) {
            const file = e.target.files[0];
            if (!file || !file.type.startsWith('image/')) return;
            const reader = new FileReader();
            reader.onload = function(ev) {
                /* Replace existing img tag */
                let img = document.querySelector('.ap-profile-float .ap-avatar-img');
                if (img) {
                    img.src = ev.target.result;
                } else {
                    /* If placeholder div exists, swap it for an img */
                    const placeholder = document.querySelector('.ap-profile-float .ap-avatar-placeholder');
                    if (placeholder) {
                        const newImg = document.createElement('img');
                        newImg.src = ev.target.result;
                        newImg.className = 'ap-avatar-img';
                        placeholder.parentNode.replaceChild(newImg, placeholder);
                    }
                }
            };
            reader.readAsDataURL(file);
        });
    }

    /* ── Tab activation based on URL query/hash ── */
    function activateTabFromLocation() {
        var params = new URLSearchParams(window.location.search);
        var tabFromQuery = params.get('tab');
        var hash = window.location.hash;
        var tabFromHash = hash ? hash.substring(1) : null;
        var tabFromServer = "";
        var tabId = tabFromQuery || tabFromHash || tabFromServer || 'general_info';

        var tabMapping = {
            'employment': '#employment',
            'achievements': '#achievements',
            'general_info': '#general_info',
            'general': '#general_info'
        };

        var targetTab = tabMapping[tabId] || '#general_info';
        var tabLink = document.querySelector('a[href="' + targetTab + '"]');
        if (tabLink) {
            if (window.bootstrap && bootstrap.Tab) {
                var tab = new bootstrap.Tab(tabLink);
                tab.show();
            } else {
                // Fallback when bootstrap.Tab is unavailable
                document.querySelectorAll('.ap-seg-bar .nav-link').forEach(function(link) {
                    link.classList.remove('active');
                });
                document.querySelectorAll('.tab-content .tab-pane').forEach(function(pane) {
                    pane.classList.remove('show', 'active');
                });
                tabLink.classList.add('active');
                var pane = document.querySelector(targetTab);
                if (pane) {
                    pane.classList.add('show', 'active');
                }
            }

            setTimeout(function() {
                var tabBody = document.querySelector('.ap-tab-body');
                if (tabBody) {
                    tabBody.scrollIntoView({ behavior: 'smooth', block: 'start' });
                }
            }, 100);
        }
    }

    // Activate tab on page load
    activateTabFromLocation();

    // Also handle hash changes (when user clicks browser back/forward)
    window.addEventListener('hashchange', activateTabFromLocation);

    // Update hash when tabs are clicked (for browser history)
    document.querySelectorAll('a[data-bs-toggle="tab"]').forEach(function(link) {
        link.addEventListener('shown.bs.tab', function(e) {
            var href = e.target.getAttribute('href');
            if (href && href.startsWith('#')) {
                // Update URL hash without scrolling
                if (history.pushState) {
                    history.pushState(null, null, href);
                } else {
                    window.location.hash = href.substring(1);
                }
            }
        });
    });
});
